   290→    const candidates = getPendingCandidates().slice(0, 5);
   291→    if (candidates.length) {
   292→      candidateSlugs.push(...candidates.map((c) => c.slug));
   293→      prompt +=
   294→        `\n\n【Query Auto-save 候選】以下回覆被自動判定值得存為 query page，` +
   295→        `請各產出一頁 wiki/queries/<slug>.md（frontmatter type: query，規則同上）：\n` +
   296→        candidates.map((c) => `- ${c.slug} — ${c.summary}`).join("\n");
   297→    }
   298→  } catch (err) {
   299→    console.warn("[wikisync] auto-save candidates read failed:", err);
   300→  }
   301→
   302→  return { prompt, rippleTopics, candidateSlugs };
