 * Check if a new fact is semantically similar to existing facts using
 * Jaccard word-set similarity. Returns the most similar existing fact
 * text if similarity > 0.7, or null if no duplicate found.
 */
function checkDuplicate(newFact: string, existingFacts: string[]): string | null {
  if (existingFacts.length === 0) return null;
  const newWords = wordSet(newFact);
  if (newWords.size < 3) return null; // too short to meaningfully compare
  let bestScore = 0;
  let bestFact = "";
  for (const existing of existingFacts) {
    const existWords = wordSet(existing);
    const intersection = new Set([...newWords].filter((w) => existWords.has(w)));
    const union = new Set([...newWords, ...existWords]);
    const jaccard = union.size > 0 ? intersection.size / union.size : 0;
    if (jaccard > bestScore) {
      bestScore = jaccard;
      bestFact = existing;
    }
  }
  return bestScore >= 0.7 ? bestFact : null;
}

function wordSet(text: string): Set<string> {
  return new Set(
    text.toLowerCase().replace(/[^\w\u4e00-\u9fff]+/g, " ").trim().split(/\s+/).filter(Boolean)
  );
}

/** Lightweight access tracking for the decay mechanism.
 *  Appends one JSONL line per query to fact-access-log.jsonl.
 *  Fire-and-forget — failures are silently ignored. */
function trackAccess(query: string, hitCount: number): void {
  try {
    const logPath = path.join(MEMORY_DIR, "fact-access-log.jsonl");
    const entry = JSON.stringify({ ts: new Date().toISOString(), q: query, hits: hitCount }) + "\n";
    appendFile(logPath, entry, "utf8").catch(() => {});
  } catch { /* best-effort */ }
}

async function listFacts(opts: { tail?: number; query?: string; explicitTail?: boolean } = {}): Promise<{
  facts: string[];
  matched: number;
  total: number;
  matchedTopic: string | null;
  viaShard: boolean;
}> {
  const userId = activeUserId();
  // Lazily load master log contents. Most topic queries skip this entirely
  // thanks to the shard fast-path.
  let masterLines: string[] | null = null;
  const loadMaster = async (): Promise<string[]> => {
    if (masterLines) return masterLines;
    try {
      const raw = await readFile(factsPath(userId), "utf8");
      masterLines = raw
        .split(/\r?\n/)
        .map(stripFactPrefix)
        .filter((s) => s.length > 0);
    } catch {
      masterLines = [];
    }
    return masterLines;
  };

