/**
 * loop-state.ts — 讀取 /dream 產出的三層 Loop State（${MEMORY_DIR}/STATE.md）。
 *
 * STATE.md 格式由 dream.ts 的 statePrompt 約定：
 *   # Loop State — telegram-kiro-bridge
 *   Last run: <ISO timestamp>
 *   ## High Priority (action needed)
 *   - 項目…（或「— 無」）
 *   ## Watch List (monitor) / ## Noise (ignored this run)
 *
 * 呼叫者：
 *   • sessionManager.create() — preamble 注入 [Pending dream suggestions] block
 *   • index.ts DT callback — dream 報告按鈕點擊時把 High Priority 丟給 agent
 *
 * 全部 fail-open：檔案缺失 / 格式不符 → 回 null，不拋錯。
 */
import { readFileSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";

export interface LoopStateHighPriority {
  lastRun: Date | null;
  /** dash-list 項目（已去掉「— 無」佔位）。可能為空陣列。 */
  items: string[];
}

export function loopStatePath(): string {
  return path.join(config.memoryDir, "STATE.md");
}

/** 讀 STATE.md 並抽出 High Priority 項目。檔案不存在或無 High Priority
 *  section 時回 null。 */
export function readLoopStateHighPriority(): LoopStateHighPriority | null {
  let raw: string;
  try {
    raw = readFileSync(loopStatePath(), "utf8");
  } catch {
    return null;
  }

  const lastRunMatch = raw.match(/^Last run:\s*(.+)$/m);
  let lastRun: Date | null = null;
  if (lastRunMatch) {
    const d = new Date(lastRunMatch[1].trim());
    if (!Number.isNaN(d.getTime())) lastRun = d;
  }

  // 取 `## High Priority` 到下一個 `## ` heading 之間的內容
  const sectionMatch = raw.match(/^## High Priority[^\n]*\n([\s\S]*?)(?=^## |\Z)/m);
  if (!sectionMatch) return null;

  const items = sectionMatch[1]
    .split(/\r?\n/)
    .map((l) => l.trim())
    .filter((l) => l.startsWith("- "))
    .map((l) => l.slice(2).trim())
    // dream 約定「某段沒東西就寫『— 無』」——不算實際項目
    .filter((l) => l.length > 0 && l !== "— 無" && l !== "—" && l !== "無");

  return { lastRun, items };
}

