/**
 * /dream, /dailylog, /artifactcleanup, /utilityreport command handlers.
 * Extracted from index.ts (P1 split).
 */
import { Context } from "grammy";
import path from "node:path";
import { readdir, unlink } from "node:fs/promises";
import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { config } from "../config.js";
import { loadDream } from "../dream-config.js";
import { getHitStats } from "../hit-log.js";
import { listTopicShards } from "../facts-store.js";
import { findStaleIndexes } from "../page-index.js";
import { rotateEventLog, getToolUsageStats } from "../event-log.js";
import { getActivitySummary } from "../activity-log.js";
import { deps } from "./deps.js";
import { formatSharedSyncResult, syncSharedKnowledge } from "../shared-sync.js";
import { readLoopStateHighPriority, loopStatePath } from "../loop-state.js";

const MEMORY_DIR = config.memoryDir;

function buildSharedReviewPrompt(sharedDir: string, files: string[]): string {
  const absPaths = files
    .slice(0, 20)
    .map((file) => path.join(sharedDir, file));
  const more = files.length > absPaths.length ? `\n另有 ${files.length - absPaths.length} 個檔案未列入本次自動審閱。` : "";
  return (
    `[系統] shared knowledge repo 剛 pull 到新/更新的 Markdown 頁面。\n` +
    `請逐一用 read tool 讀取下列檔案，判斷是否值得內化成本機 memory/wiki。\n\n` +
    absPaths.map((file) => `- ${file}`).join("\n") +
    more +
    `\n\n規則：\n` +
    `- 不要只憑檔名判斷；必須讀檔後再下結論。\n` +
    `- 只處理穩定、可重用、跨 session 仍有價值的知識。\n` +
    `- 若適合 memory，提出一行可 remember 的 fact，並說明 topic 建議。\n` +
    `- 若適合 wiki，提出目標 slug/type 與摘要。\n` +
    `- 若內容不適合內化，說明跳過原因。\n` +
    `- intel-learning/ 路徑下的檔案視為已批准素材，自行判斷：有 project impact + actionable 啟發 → 直接 remember（精煉成一條含啟發的 fact，topic=ai-research）；純公告/純 benchmark 無啟發/場景距離太遠 → 跳過，不需問使用者確認。\n` +
    `- 其他路徑的檔案：預設先輸出候選與建議，不要靜默寫入 memory/wiki。\n` +
    `- 用繁體中文回覆。`
  );
}

async function triggerSharedReview(ctx: Context, sharedDir: string, files: string[]): Promise<void> {
  if (files.length === 0) return;
  const { sessions, runPrompt } = deps();
  const chatId = ctx.chat?.id;
  if (!chatId) return;
  try {
    const session = await sessions.get(chatId, ctx.from?.id);
    await runPrompt(ctx, session, buildSharedReviewPrompt(sharedDir, files), { kind: "meta" });
  } catch (err) {
    await ctx.reply(`⚠️ shared review 啟動失敗：${(err as Error).message.slice(0, 300)}`);
  }
}

// ─── /dream ────────────────────────────────────────────────────────────────

export async function handleDream(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt, commandHandlers } = deps();
  if (!isAllowed(ctx)) return;

  const cfg = loadDream();
  const sourceTag = cfg.source === "file"
    ? `（config: ${cfg.configPath}）`
    : `（default，無 config 檔）`;

  for (const w of cfg.warnings) {
    if (cfg.source === "default" && /不存在/.test(w)) continue;
    await ctx.reply(`⚠ dream: ${w}`);
  }

  const resolved = cfg.steps.map((s) => ({
    cmd: s.cmd,
    label: s.label,
    fn: commandHandlers[s.cmd],
  }));
  const unknown = resolved.filter((s) => !s.fn);
  if (unknown.length > 0) {
    await ctx.reply(
      `⚠ dream: 未知指令已跳過：${unknown.map((s) => s.cmd).join(", ")}`,
    );
  }
  const runnable = resolved.filter((s) => s.fn);
  if (runnable.length === 0) {
    await ctx.reply(`❌ dream 沒有可執行步驟。`);
    return;
  }

  await ctx.reply(
    `🌙 Dream routine 開始，共 ${runnable.length} 步 ${sourceTag}`,
  );

  const stepResults: Array<{ cmd: string; ok: boolean; summary: string; result?: import("../dream-config.js").DreamStepResult }> = [];

  const chatId = ctx.chat!.id;
  let session: import("../sessionManager.js").ChatSession | null = null;
  try { session = await sessions.get(chatId, ctx.from?.id); } catch { /* ok */ }

  for (let i = 0; i < runnable.length; i++) {
    const step = runnable[i];
    const labelPart = step.label ? ` — ${step.label}` : "";
    try {
      await ctx.reply(
        `▶ Step ${i + 1}/${runnable.length}: /${step.cmd}${labelPart}`,
      );
      if (step.cmd === "restart") {
        break;
      }

      // Capture session buffer before running the step
      const bufferBefore = session?.buffer ?? "";
      const result: any = await step.fn!(ctx);

      let summary: string;
      let structuredResult: import("../dream-config.js").DreamStepResult | undefined;

      if (result && typeof result === "object" && "summary" in result) {
        // Handler returned structured result — use directly
        structuredResult = result as import("../dream-config.js").DreamStepResult;
        summary = structuredResult.summary;
      } else if (session && session.buffer !== bufferBefore) {
        // Agent produced output — use last buffer content directly (truncated)
        // This is the agent's actual work output, much better than asking it to summarize itself
        const rawOutput = session.buffer.trim();
        summary = rawOutput.slice(0, 400) || "(no output)";
      } else {
        summary = "(no output)";
      }

      stepResults.push({ cmd: step.cmd, ok: true, summary, result: structuredResult });
    } catch (err) {
      const msg = (err as Error).message;
      await ctx.reply(
        `⚠ Step ${i + 1}/${runnable.length} /${step.cmd} 失敗：${msg}`,
      );
      stepResults.push({ cmd: step.cmd, ok: false, summary: msg });
      if (!cfg.continue_on_error) {
        await ctx.reply(
          `🛑 continue_on_error=false，中斷剩餘 ${runnable.length - i - 1} 步。`,
        );
        break;
      }
    }
  }

  // Generate final dream summary report
  try {
    let dreamReport = "📋 Dream 綜合報告\n━━━━━━━━━━━━━━━━━━━\n";

    // 24h 活動摘要（統一活動流：hit-log / event-log / observations）
    try {
      const act = getActivitySummary(24);
      if (act.total > 0) {
        dreamReport +=
          `📈 24h 活動：${act.total} 筆` +
          `（hit ${act.bySource.hit} / event ${act.bySource.event} / tool ${act.bySource.observation}` +
          `；fact 命中 ${act.factHits}、wiki 命中 ${act.wikiHits}）\n`;
      }
    } catch { /* 旁路訊號，讀取失敗不影響報告 */ }

    const allActionItems: string[] = [];

    for (const r of stepResults) {
      const icon = r.ok ? "✅" : "❌";
      // Use structured result's summary if available, else use captured buffer summary
      const displaySummary = r.result?.summary ?? r.summary.slice(0, 200);
      dreamReport += `${icon} /${r.cmd}：${displaySummary}\n`;

      // Collect action items from structured results
      if (r.result?.actionItems) {
        allActionItems.push(...r.result.actionItems.map(a => `[/${r.cmd}] ${a}`));
      }
    }

    // If we have structured action items, list them directly (no LLM needed)
    if (allActionItems.length > 0) {
      dreamReport += `\n🎯 需要處理的項目（${allActionItems.length}）：\n`;
      dreamReport += allActionItems.map((a, i) => `${i + 1}. ${a}`).join("\n");
    }

    // Only ask LLM for suggestions if there are agent-based steps with substantial output
    // and no structured action items already cover the situation
    const agentSteps = stepResults.filter(r => r.ok && !r.result && r.summary.length > 50);
    if (session && agentSteps.length > 0) {
      const stepsText = agentSteps
        .map(r => `/${r.cmd}：${r.summary.slice(0, 300)}`)
        .join("\n");
      await runPrompt(ctx, session,
        `以下是 dream routine 各 agent 步驟的直接輸出摘要：\n${stepsText}\n\n` +
        `請只列出「需要人工處理」的項目（如果有的話），格式：\n` +
        `每項一行「- [emoji] 具體描述（來源：/步驟名）」\n` +
        `emoji：🔺升格 ⚠️矛盾 ✂️拆分 🗑️清理 📝更新 🐛問題\n` +
        `如果沒有需要人工處理的就回「✨ 系統健康，無需額外動作。」\n` +
        `不要重複上面已列出的內容。精簡回答，不要解釋。`,
        { kind: "meta", silent: true },
      );
      const actionText = (session.buffer || "").trim();
      if (actionText && !actionText.includes("無需額外動作")) {
        dreamReport += `\n\n🤖 建議：\n${actionText}`;
      }
    }

    if (allActionItems.length === 0 && !dreamReport.includes("建議")) {
      dreamReport += "\n\n✨ 系統健康，無需額外動作。";
    }

    try {
      await ctx.reply(dreamReport);
    } catch {
      await ctx.reply(dreamReport.replace(/\*\*/g, "").replace(/━+/g, "---"));
    }
    await ctx.reply(`✅ Dream routine 完成（${stepResults.filter(r => r.ok).length}/${runnable.length}）。`);
  } catch (reportErr) {
    console.error("[dream] report generation failed:", reportErr);
    await ctx.reply(`✅ Dream routine 完成（報告產出失敗：${(reportErr as Error).message}）`).catch(() => {});
  }

  // ── Write STATE.md (three-tier loop state) ──
  try {
    if (session && stepResults.length > 0) {
      const statePrompt =
        `以下是今天 dream routine 各步驟結果：\n` +
        stepResults.map(r => `${r.ok ? "✅" : "❌"} /${r.cmd}：${r.summary}`).join("\n") +
        `\n\n請根據上述結果，產出三段式 Loop State。格式嚴格如下（直接輸出 Markdown，不要包在 code block）：\n\n` +
        `# Loop State — telegram-kiro-bridge\n` +
        `Last run: ${new Date().toISOString()}\n\n` +
        `## High Priority (action needed)\n` +
        `- （需要人工介入的項目：矛盾待確認、失敗步驟、skill orphan、膨脹警告等）\n\n` +
        `## Watch List (monitor)\n` +
        `- （值得關注但不急的：沉默 topic、wiki 過期、pending 升格候選等）\n\n` +
        `## Noise (ignored this run)\n` +
        `- （正常完成、無需關注的：backup 成功、artifact 清理等）\n\n` +
        `規則：\n` +
        `- 每段只列有內容的項目（1 行 1 項，dash list）\n` +
        `- 失敗步驟一律進 High Priority\n` +
        `- 某段沒東西就寫「— 無」\n` +
        `- 全文 ≤30 行\n` +
        `- 不要加任何額外說明`;
      await runPrompt(ctx, session, statePrompt, { kind: "meta", silent: true });
      const stateContent = (session.buffer || "").trim();
      if (stateContent && stateContent.includes("## High Priority")) {
        const statePath = path.join(MEMORY_DIR, "STATE.md");
        writeFileSync(statePath, stateContent + "\n", "utf8");
      }
    }
  } catch (stateErr) {
    console.error("[dream] STATE.md write failed:", stateErr);
  }

  // Daily event log rotation
  try {
    const { deleted, kept } = rotateEventLog();
    if (deleted > 0) {
      await ctx.reply(`🗑 Event log 清理：刪除 ${deleted} 筆舊事件，保留 ${kept} 筆。`);
    }
  } catch (err) {
    console.error("[dream] event log rotation failed:", err);
  }

  // Execute restart as the very last thing
  if (runnable.some(s => s.cmd === "restart")) {
    if (session?.inflight) {
      await ctx.reply("⏳ 等待上一步完成...");
      const deadline = Date.now() + 60_000;
      while (session.inflight && Date.now() < deadline) {
        await new Promise(r => setTimeout(r, 1000));
      }
    }
    const handleRestart = commandHandlers["restart"];
    if (handleRestart) await handleRestart(ctx);
  }
}

// ─── /dailylog ─────────────────────────────────────────────────────────────

export async function handleDailyLog(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;

  const rawArg = typeof ctx.match === "string" ? ctx.match.trim() : "";
  const dateMatch = rawArg.match(/^(\d{4}-\d{2}-\d{2})$/);
  const targetDate = dateMatch ? dateMatch[1] : new Date().toISOString().slice(0, 10);

  const sessDir = path.join(MEMORY_DIR, "sessions");
  const oldSessDir = path.join(MEMORY_DIR, "oldSessions");
  const prefix = `session-${chatId}-${targetDate}`;

  const [curr, old] = await Promise.all([
    readdir(sessDir).catch(() => [] as string[]),
    readdir(oldSessDir).catch(() => [] as string[]),
  ]);
  const todayFiles = [
    ...curr.filter((f) => f.startsWith(prefix) && f.endsWith(".md")).map((f) => path.join(sessDir, f)),
    ...old.filter((f) => f.startsWith(prefix) && f.endsWith(".md")).map((f) => path.join(oldSessDir, f)),
  ].sort();

  if (todayFiles.length === 0) {
    await ctx.reply(`📓 ${targetDate} 沒有 session 記錄，跳過 dailylog。`);
    return;
  }

  const logDir = path.join(MEMORY_DIR, "dailylog");
  const { mkdir } = await import("node:fs/promises");
  await mkdir(logDir, { recursive: true });

  const fileList = todayFiles.map((p) => `- ${p}`).join("\n");
  const outPath = path.join(logDir, targetDate + ".md");

  const prompt =
    `請產出 ${targetDate} 的 daily log。\n` +
    `以下是該日的 session 檔案，請逐一讀取後產出精簡摘要：\n${fileList}\n\n` +
    `輸出檔案路徑：${outPath}\n` +
    "格式：\n" +
    "```markdown\n" +
    `# ${targetDate}\n\n` +
    "## 完成\n- （列出當天完成的事項，每項一行）\n\n" +
    "## 進行中\n- （列出未完成但有進展的事項）\n\n" +
    "## 筆記\n- （值得記錄的發現、決策、數據）\n" +
    "```\n\n" +
    "規則：\n" +
    "- 總長度 ≤30 行，精簡扼要\n" +
    "- 跳過 trivial 的打招呼、確認收到等\n" +
    "- 如果 session 內容為空或只有幾句閒聊，該 session 可跳過\n" +
    "- 用繁體中文\n" +
    "- 直接寫入檔案（覆蓋已存在的），寫完後回報完成";

  let session: import("../sessionManager.js").ChatSession;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(`❌ dailylog 失敗：${(err as Error).message}`);
    return;
  }
  await runPrompt(ctx, session, prompt, { kind: "meta" });
}

// ─── /artifactcleanup ──────────────────────────────────────────────────────

export async function handleArtifactCleanup(ctx: Context): Promise<import("../dream-config.js").DreamStepResult | void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const dir = path.join(config.memoryDir, "artifacts");
  let deleted = 0;
  let remaining = 0;
  try {
    const files = await readdir(dir).catch(() => [] as string[]);
    const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
    for (const f of files) {
      if (!f.endsWith(".json")) continue;
      const dateStr = f.slice(0, 10);
      const ts = new Date(dateStr).getTime();
      if (!isNaN(ts) && ts < cutoff) {
        await unlink(path.join(dir, f));
        deleted++;
      }
    }
    remaining = files.length - deleted;
    await ctx.reply(`🧹 Artifact cleanup：刪除 ${deleted} 個超過 7 天的檔案（剩餘 ${remaining} 個）`);
  } catch (err: any) {
    await ctx.reply(`❌ artifact cleanup 失敗：${err.message}`);
    return;
  }

  // Stale index report
  const staleIndexes: string[] = [];
  try {
    const stale = findStaleIndexes(MEMORY_DIR, 30);
    if (stale.length > 0) {
      staleIndexes.push(...stale.map((s) => `${s.slug}: ${s.title} (created ${s.created_at.slice(0, 10)})`));
      const lines = stale.map((s) => `  - ${s.slug}: ${s.title} (created ${s.created_at.slice(0, 10)})`);
      await ctx.reply(`📚 Stale indexes（>30天未查詢，建議清理）：\n${lines.join("\n")}`);
    }
  } catch { /* non-critical */ }

  return {
    summary: `刪除 ${deleted} 個舊 artifact，剩餘 ${remaining} 個${staleIndexes.length ? `；${staleIndexes.length} 個 stale index` : ""}`,
    metrics: { deleted, remaining, staleIndexes: staleIndexes.length },
    actionItems: staleIndexes.length > 0 ? staleIndexes.map(s => `清理 stale index: ${s}`) : undefined,
  };
}

// ─── /docupdate ────────────────────────────────────────────────────────────

